import { useState } from "react";
import axios from "axios";

export default function Register() {

  const [form, setForm] = useState({
    role: "customer",
    skills: []
  });

  const jobs = [
    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"
  ];

  const handleSkills = (e) => {

    const values = Array.from(
      e.target.selectedOptions,
      option => option.value
    );

    setForm({
      ...form,
      skills: values
    });
  };

  const register = async () => {

    try {

      const res = await axios.post(
        "http://localhost:5000/api/auth/register",
        form
      );

      localStorage.setItem(
        "user",
        JSON.stringify(res.data)
      );

      if (form.role === "customer") {

        window.location = "/customer";

      } else {

        window.location = "/labour";
      }

    } catch (err) {

      alert("Registration Failed");
    }
  };

  return (

    <div style={styles.page}>

      <div style={styles.card}>

        <h1 style={styles.title}>
          Register
        </h1>

        {/* ROLE */}

        <select
          style={styles.input}
          onChange={(e) =>
            setForm({
              ...form,
              role: e.target.value
            })
          }
        >

          <option value="customer">
            Customer
          </option>

          <option value="labour">
            Labour
          </option>

        </select>

        {/* NAME */}

        <input
          style={styles.input}
          placeholder="Full Name"
          onChange={(e) =>
            setForm({
              ...form,
              name: e.target.value
            })
          }
        />

        {/* EMAIL */}

        <input
          style={styles.input}
          placeholder="Email"
          onChange={(e) =>
            setForm({
              ...form,
              email: e.target.value
            })
          }
        />

        {/* PASSWORD */}

        <input
          type="password"
          style={styles.input}
          placeholder="Password"
          onChange={(e) =>
            setForm({
              ...form,
              password: e.target.value
            })
          }
        />

        {/* PHONE */}

        <input
          style={styles.input}
          placeholder="Phone Number"
          onChange={(e) =>
            setForm({
              ...form,
              phone: e.target.value
            })
          }
        />

        {/* CITY */}

        <input
          style={styles.input}
          placeholder="City"
          onChange={(e) =>
            setForm({
              ...form,
              city: e.target.value
            })
          }
        />

        {/* AREA */}

        <input
          style={styles.input}
          placeholder="Area"
          onChange={(e) =>
            setForm({
              ...form,
              area: e.target.value
            })
          }
        />

        {/* ADDRESS */}

        <textarea
          style={styles.textarea}
          placeholder="Full Address"
          onChange={(e) =>
            setForm({
              ...form,
              address: e.target.value
            })
          }
        />

        {/* LABOUR */}

        {form.role === "labour" && (

          <>

            <label style={styles.label}>
              Select Jobs
            </label>

            <select
              multiple
              style={styles.multi}
              onChange={handleSkills}
            >

              {jobs.map((job, i) => (

                <option key={i} value={job}>
                  {job}
                </option>

              ))}

            </select>

            <input
              style={styles.input}
              placeholder="Base Price"
              onChange={(e) =>
                setForm({
                  ...form,
                  price: e.target.value
                })
              }
            />

          </>
        )}

        <button
          style={styles.button}
          onClick={register}
        >
          Register
        </button>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    background: "#f5f7fb"
  },

  card: {
    width: "420px",
    background: "white",
    padding: "35px",
    borderRadius: "15px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.06)"
  },

  title: {
    marginBottom: "20px"
  },

  input: {
    width: "100%",
    padding: "14px",
    marginBottom: "15px",
    borderRadius: "8px",
    border: "1px solid #ddd"
  },

  textarea: {
    width: "100%",
    height: "90px",
    padding: "14px",
    marginBottom: "15px",
    borderRadius: "8px",
    border: "1px solid #ddd",
    resize: "none"
  },

  multi: {
    width: "100%",
    height: "120px",
    marginBottom: "15px",
    borderRadius: "8px",
    border: "1px solid #ddd"
  },

  label: {
    marginBottom: "8px",
    display: "block"
  },

  button: {
    width: "100%",
    padding: "14px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  }

};
